import{_ as e,c as t,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Invalid Grant 排查: 账号禁用恢复 | Antigravity-Manager","description":"学习 invalid_grant 错误的含义与自动处理逻辑。确认 refresh_token 失效后，通过重新 OAuth 添加账号触发自动解禁，并验证恢复对 Proxy 生效。","frontmatter":{"title":"Invalid Grant 排查: 账号禁用恢复 | Antigravity-Manager","sidebarTitle":"账号被禁用了怎么恢复","subtitle":"invalid_grant 与账号自动禁用：为什么会发生、如何恢复","description":"学习 invalid_grant 错误的含义与自动处理逻辑。确认 refresh_token 失效后，通过重新 OAuth 添加账号触发自动解禁，并验证恢复对 Proxy 生效。","tags":["FAQ","错误排查","OAuth","账号管理","invalid_grant"],"prerequisite":["start-add-account","start-first-run-data","advanced-scheduling"],"order":1},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"}'),o={name:"zh/lbjlaq/Antigravity-Manager/faq/invalid-grant/index.md"};function d(n,a,s,l,c,h){return r(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="invalid-grant-与账号自动禁用-为什么会发生、如何恢复" tabindex="-1">invalid_grant 与账号自动禁用：为什么会发生、如何恢复 <a class="header-anchor" href="#invalid-grant-与账号自动禁用-为什么会发生、如何恢复" aria-label="Permalink to &quot;invalid_grant 与账号自动禁用：为什么会发生、如何恢复&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>看到 <code>invalid_grant</code> 时，知道它对应的是哪一类 refresh_token 问题</li><li>弄清楚“账号为什么突然不可用”：什么情况下会被自动禁用、禁用后系统怎么处理</li><li>用最短路径恢复账号，并确认恢复已经对正在运行的 Proxy 生效</li></ul><h2 id="你遇到的症状" tabindex="-1">你遇到的症状 <a class="header-anchor" href="#你遇到的症状" aria-label="Permalink to &quot;你遇到的症状&quot;">​</a></h2><ul><li>调用本地 Proxy 时突然失败，错误信息里出现 <code>invalid_grant</code></li><li>明明账号还在 Accounts 列表里，但 Proxy 总是跳过它（或者你感觉它“再也没被用到”）</li><li>只有少量账号时，遇到一次 <code>invalid_grant</code> 后，整体可用性明显变差</li></ul><h2 id="什么是-invalid-grant" tabindex="-1">什么是 invalid_grant？ <a class="header-anchor" href="#什么是-invalid-grant" aria-label="Permalink to &quot;什么是 invalid_grant？&quot;">​</a></h2><p><strong>invalid_grant</strong> 是 Google OAuth 在刷新 <code>access_token</code> 时返回的一类错误。对 Antigravity Tools 来说，它意味着某个账号的 <code>refresh_token</code> 很可能已经被撤销或过期，继续重试只会反复失败，所以系统会把该账号标记为不可用并从代理池中移出。</p><h2 id="核心思路-系统不是-临时跳过-而是-持久禁用" tabindex="-1">核心思路：系统不是“临时跳过”，而是“持久禁用” <a class="header-anchor" href="#核心思路-系统不是-临时跳过-而是-持久禁用" aria-label="Permalink to &quot;核心思路：系统不是“临时跳过”，而是“持久禁用”&quot;">​</a></h2><p>当 Proxy 发现刷新 token 的错误字符串包含 <code>invalid_grant</code> 时，会做两件事：</p><ol><li><strong>把账号写成 disabled</strong>（落盘到账号 JSON）</li><li><strong>把账号从内存 token pool 移除</strong>（避免反复选中同一个坏账号）</li></ol><p>这就是你看到“账号还在，但 Proxy 不再用它”的原因。</p><div class="info custom-block"><p class="custom-block-title">disabled vs proxy_disabled</p><ul><li><code>disabled=true</code>：账号被“彻底禁用”（典型原因就是 <code>invalid_grant</code>）。加载账号池时会直接跳过。</li><li><code>proxy_disabled=true</code>：账号只是“对 Proxy 不可用”（手动禁用/批量操作/配额保护相关逻辑），语义不同。</li></ul><p>这两个状态在加载账号池时是分开判断的：先判断 <code>disabled</code>，再做配额保护与 <code>proxy_disabled</code> 判断。</p></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-确认是不是-refresh-token-刷新触发的-invalid-grant" tabindex="-1">第 1 步：确认是不是 refresh_token 刷新触发的 invalid_grant <a class="header-anchor" href="#第-1-步-确认是不是-refresh-token-刷新触发的-invalid-grant" aria-label="Permalink to &quot;第 1 步：确认是不是 refresh_token 刷新触发的 invalid_grant&quot;">​</a></h3><p><strong>为什么</strong>：<code>invalid_grant</code> 可能出现在多个调用链路里，但本项目的“自动禁用”只在<strong>刷新 access_token 失败</strong>时触发。</p><p>在 Proxy 日志里，你会看到类似的错误日志（关键词是 <code>Token 刷新失败</code> + <code>invalid_grant</code>）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Token 刷新失败 (&lt;email&gt;): &lt;...invalid_grant...&gt;，尝试下一个账号</span></span>
<span class="line"><span>Disabling account due to invalid_grant (&lt;email&gt;): refresh_token likely revoked/expired</span></span></code></pre></div><p><strong>你应该看到</strong>：同一个账号在出现 <code>invalid_grant</code> 后，很快就不再被选中（因为它被移出 token pool）。</p><h3 id="第-2-步-在账号文件里检查-disabled-字段-可选-但最准确" tabindex="-1">第 2 步：在账号文件里检查 disabled 字段（可选，但最准确） <a class="header-anchor" href="#第-2-步-在账号文件里检查-disabled-字段-可选-但最准确" aria-label="Permalink to &quot;第 2 步：在账号文件里检查 disabled 字段（可选，但最准确）&quot;">​</a></h3><p><strong>为什么</strong>：自动禁用是“落盘”的，你确认文件内容后，就能排除“只是临时轮换”的误判。</p><p>账号文件位于应用数据目录的 <code>accounts/</code> 目录下（数据目录位置见 <strong><a href="./../../start/first-run-data/">首次启动必懂：数据目录、日志、托盘与自动启动</a></strong>）。当账号被禁用时，文件会出现这三个字段：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1700000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;disabled_reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;invalid_grant: ...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>你应该看到</strong>：<code>disabled</code> 为 <code>true</code>，并且 <code>disabled_reason</code> 里包含 <code>invalid_grant:</code> 前缀。</p><h3 id="第-3-步-恢复账号-推荐做法-重新添加同一个账号" tabindex="-1">第 3 步：恢复账号（推荐做法：重新添加同一个账号） <a class="header-anchor" href="#第-3-步-恢复账号-推荐做法-重新添加同一个账号" aria-label="Permalink to &quot;第 3 步：恢复账号（推荐做法：重新添加同一个账号）&quot;">​</a></h3><p><strong>为什么</strong>：本项目的“恢复”不是在 Proxy 里手动点一个开关，而是通过“显式更新 token”来触发自动解禁。</p><p>到 <strong>Accounts</strong> 页面，用你新的凭据重新添加账号（两种方式任选其一）：</p><ol><li>重新走 OAuth 授权流程（见 <strong><a href="./../../start/add-account/">添加账号：OAuth/Refresh Token 双通道与最佳实践</a></strong>）</li><li>用新的 <code>refresh_token</code> 再添加一次（系统会以 Google 返回的邮箱为准做 upsert）</li></ol><p>当系统检测到你这次 upsert 的 <code>refresh_token</code> 或 <code>access_token</code> 与旧值不同，并且该账号之前处于 <code>disabled=true</code>，会自动清掉：</p><ul><li><code>disabled</code></li><li><code>disabled_reason</code></li><li><code>disabled_at</code></li></ul><p><strong>你应该看到</strong>：账号不再处于 disabled 状态，并且（如果 Proxy 正在运行）账号池会被自动 reload，让恢复立即生效。</p><h3 id="第-4-步-验证恢复是否已对-proxy-生效" tabindex="-1">第 4 步：验证恢复是否已对 Proxy 生效 <a class="header-anchor" href="#第-4-步-验证恢复是否已对-proxy-生效" aria-label="Permalink to &quot;第 4 步：验证恢复是否已对 Proxy 生效&quot;">​</a></h3><p><strong>为什么</strong>：如果你只有一个账号，或者其他账号也不可用，恢复后你应该立刻看到“可用性回来了”。</p><p>验证方法：</p><ol><li>发起一次会触发 token 刷新的请求（例如等待 token 临近过期后再请求）</li><li>观察日志不再出现“跳过 disabled 账号”的提示</li></ol><p><strong>你应该看到</strong>：请求能正常通过，且日志里不再出现针对该账号的 <code>invalid_grant</code> 禁用流程。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="❌-把-disabled-当成-临时轮换" tabindex="-1">❌ 把 disabled 当成“临时轮换” <a class="header-anchor" href="#❌-把-disabled-当成-临时轮换" aria-label="Permalink to &quot;❌ 把 disabled 当成“临时轮换”&quot;">​</a></h3><p>如果你只在 UI 里看“账号还在”，很容易误判为“系统只是暂时不用它”。但 <code>disabled=true</code> 是写到磁盘上的，重启后也会继续生效。</p><h3 id="❌-只补充-access-token-不更新-refresh-token" tabindex="-1">❌ 只补充 access_token，不更新 refresh_token <a class="header-anchor" href="#❌-只补充-access-token-不更新-refresh-token" aria-label="Permalink to &quot;❌ 只补充 access_token，不更新 refresh_token&quot;">​</a></h3><p><code>invalid_grant</code> 的触发点是刷新 <code>access_token</code> 时使用的 <code>refresh_token</code>。如果你只是临时拿到了一个还能用的 <code>access_token</code>，但 <code>refresh_token</code> 依旧失效，后续还是会再次触发禁用。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>[ ] 你能在日志里确认 <code>invalid_grant</code> 来自 refresh_token 刷新失败</li><li>[ ] 你知道 <code>disabled</code> 和 <code>proxy_disabled</code> 的语义差异</li><li>[ ] 你能通过重新添加账号（OAuth 或 refresh_token）恢复账号</li><li>[ ] 你能验证恢复已经对运行中的 Proxy 生效</li></ul><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li><code>invalid_grant</code> 触发时，Proxy 会把账号 <strong>落盘为 disabled</strong>，并从 token pool 移除，避免反复失败</li><li>恢复的关键是“显式更新 token”（重新 OAuth 或用新 refresh_token 再添加一次），系统会自动清掉 <code>disabled_*</code> 字段</li><li>数据目录中的账号 JSON 是最权威的状态来源（禁用/原因/时间都在里面）</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../auth-401/">401/鉴权失败：auth_mode、Header 兼容与客户端配置清单</a></strong>。</p><p>你会学到：</p><ul><li>401 通常是“模式/Key/Header”哪一层不匹配</li><li>不同客户端该带什么鉴权 Header</li><li>如何用最短路径自检并修复</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>设计说明：invalid_grant 的问题与变更行为</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy-invalid-grant.md#L1-L52" target="_blank" rel="noreferrer"><code>docs/proxy-invalid-grant.md</code></a></td><td>1-52</td></tr><tr><td>加载账号池时跳过 <code>disabled=true</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L70-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>70-158</td></tr><tr><td>刷新 token 失败时识别 <code>invalid_grant</code> 并禁用账号</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L840-L890" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>840-890</td></tr><tr><td>持久化写入 <code>disabled/disabled_at/disabled_reason</code> 并从内存移除</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L942-L969" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>942-969</td></tr><tr><td><code>disabled_reason</code> 截断（避免账号文件膨胀）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1464-L1471" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1464-1471</td></tr><tr><td>upsert 时自动清理 <code>disabled_*</code>（token 变化即视为用户已修复凭据）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L178-L206" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>178-206</td></tr><tr><td>重新添加账号后自动 reload proxy accounts（运行中立即生效）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L21-L59" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>21-59</td></tr></tbody></table></details>`,49)])])}const u=e(o,[["render",d]]);export{p as __pageData,u as default};
